code = """import json, pandas as pd

df_cases = pd.DataFrame(var_call_6P0Dj0Rzc87wThiXGXxHwY3C)
df_acct = pd.DataFrame(var_call_ik1KcSImFl9eygdVUibpBdYQ)

# coerce numeric
for c in ['avg_closure_days','case_count']:
    df_cases[c] = pd.to_numeric(df_cases[c], errors='coerce')

df = df_cases.merge(df_acct, on='accountid_clean', how='left')
# keep valid 2-letter state
df['shipping_state'] = df['shipping_state'].astype('string').str.strip().str.upper()
df = df[df['shipping_state'].str.fullmatch(r'[A-Z]{2}', na=False)]

state_stats = df.groupby('shipping_state', as_index=False).agg(
    avg_closure_days=('avg_closure_days','mean'),
    cases=('case_count','sum'),
    accounts=('accountid_clean','nunique')
)

# quickest = smallest avg_closure_days
state_stats = state_stats.sort_values(['avg_closure_days','cases','accounts'], ascending=[True, False, False])
ans = state_stats.iloc[0]['shipping_state'] if len(state_stats) else None

print('__RESULT__:')
print(json.dumps({'state': ans}))"""

